    AND m.order_index = 2 AND l.order_index = 5
) AND type = 'reading';

-- ── Lesson 6 ────────────────────────────────────────────────
UPDATE english_lesson_sections
SET content = $json${
  "title": "A Decade of Change: Cultural Revolutions of the 1960s",
  "text": "The 1960s produced some of the most profound social and cultural changes of the twentieth century. In Western countries, particularly the United States and Britain, a new generation rejected the conservative values and institutions of the previous era and demanded radical change. The decade saw the emergence of powerful social movements that would reshape society for generations. The civil rights movement in the United States challenged racial segregation and demanded full legal equality for African Americans. The anti-Vietnam War movement mobilised millions of young people against military intervention overseas. The feminist movement challenged traditional gender roles and demanded equal rights and opportunities for women. The environmental movement raised public awareness of pollution and ecological damage. Music became a powerful vehicle for social expression. Artists including Bob Dylan, the Beatles, Janis Joplin, and Jimi Hendrix used their songs to challenge authority, celebrate freedom, and express the frustration and idealism of an entire generation. Rock, folk, and soul music carried messages of protest and hope across the world. In visual art, the Pop Art movement led by Andy Warhol questioned the boundary between high culture and mass culture. Beat writers including Jack Kerouac celebrated individual freedom, non-conformity, and the rejection of materialism. The legacy of the 1960s is complex. The movements achieved significant legal and social change: racial segregation was outlawed, voting rights were extended, and environmental legislation was enacted. However, deep inequalities persisted. The decade established a tradition of political activism and social critique that continues to shape public life and culture across the world today.",
  "glossary": [
    {"term": "counterculture", "definition": "a culture with values and lifestyles that oppose those of the mainstream society", "translation": "контркультура"},
    {"term": "activism", "definition": "the use of campaigning, protest, and direct action to bring about political or social change", "translation": "активизм"},
    {"term": "non-conformity", "definition": "the refusal to follow prevailing social norms and expectations", "translation": "нонконформизм"},
    {"term": "ecological", "definition": "relating to the relationship between living organisms and their natural environment", "translation": "экологический"},
    {"term": "materialism", "definition": "the belief that wealth and physical possessions are the most important things in life", "translation": "материализм"},
    {"term": "legislation", "definition": "laws that have been enacted by a government or legislature", "translation": "законодательство"}
  ],
  "comprehension_questions": [
    {"id": 1, "question": "What does the passage describe as the main theme of the 1960s?", "options": ["A) A decade of economic growth and technological progress", "B) A period of cultural and social stability following World War Two", "C) A decade in which young people challenged established values and demanded radical change", "D) A period of political consensus between conservative and progressive forces"], "answer": "C", "explanation": "A new generation rejected conservative values and institutions and demanded radical change, producing profound social and cultural transformations."},
    {"id": 2, "question": "Which of the following movements is NOT mentioned in the passage as part of the 1960s cultural revolution?", "options": ["A) The civil rights movement demanding racial equality", "B) The feminist movement challenging gender roles", "C) The anti-Vietnam War movement opposing military intervention", "D) A movement to restore traditional family values"], "answer": "D", "explanation": "The passage mentions civil rights, anti-war, feminist, and environmental movements — not a traditional values movement."},
    {"id": 3, "question": "What role did music play in the cultural changes of the 1960s?", "options": ["A) Music became purely commercial and avoided political themes", "B) Music served as a vehicle to challenge authority and express the idealism of a generation", "C) Music became less popular as young people turned to visual art and literature", "D) Government censorship limited the influence of protest music"], "answer": "B", "explanation": "Music was a powerful vehicle for social expression, used to challenge authority and express the frustration and idealism of an entire generation."},
    {"id": 4, "question": "What was the Pop Art movement as described in the passage?", "options": ["A) A musical movement combining popular and classical traditions", "B) A political movement using art to campaign for social change", "C) An art movement questioning the boundary between high culture and mass culture", "D) A government programme bringing art education to working-class communities"], "answer": "C", "explanation": "Pop Art, led by Andy Warhol, questioned the boundary between high culture and mass culture."},
    {"id": 5, "question": "What does the passage say about the legacy of the 1960s?", "options": ["A) The influence was short-lived and had little lasting impact", "B) Deep inequalities persisted and the movements achieved nothing significant", "C) Significant legal changes were achieved but deep inequalities persisted", "D) The impact was limited to the United States and had no global influence"], "answer": "C", "explanation": "The movements achieved significant legal and social change, but deep inequalities persisted. The decade established a lasting tradition of political activism."}
