-- ── Lesson 7 ────────────────────────────────────────────────
UPDATE english_lesson_sections
SET content = $json${
  "title": "Globalisation: From Local Traditions to a Connected World",
  "text": "Globalisation describes the accelerating process by which economies, societies, and cultures around the world have become interconnected. Although trade and cultural contact between distant regions have existed for millennia, the speed and scale of globalisation increased dramatically during the twentieth century, particularly after the end of the Cold War in 1991. Several developments drove this acceleration. Container shipping dramatically reduced the cost of transporting goods across oceans. Commercial aviation made international travel accessible to millions. The internet and mobile communication created instant global connectivity for individuals and businesses. Multinational corporations expanded across borders, producing goods in lower-wage countries and selling them in higher-income markets. This produced significant economic growth in parts of Asia, Latin America, and Africa, lifting hundreds of millions of people out of extreme poverty. Critics argue, however, that globalisation has also increased inequality. Workers in developed countries have lost jobs as manufacturing moved to cheaper locations. Workers in developing countries often face poor conditions and low wages despite contributing to global supply chains. Cultural globalisation has had similarly mixed effects. The global spread of English, American films, music, and consumer brands has created shared cultural reference points. However, it has also threatened minority languages and local traditions. Hundreds of languages are now endangered, and communities around the world struggle to preserve cultural practices against the pressure of a dominant global culture. Supporters of globalisation argue that the mixing of cultures produces new hybrid forms of music, art, and cuisine that enrich human experience. The debate about how to manage globalisation fairly and sustainably continues to define international political and economic discourse today.",
  "glossary": [
    {"term": "globalisation", "definition": "the process by which economies, cultures, and societies worldwide become increasingly interconnected", "translation": "глобализация"},
    {"term": "multinational corporation", "definition": "a large company that operates in multiple countries simultaneously", "translation": "транснациональная корпорация"},
    {"term": "homogenisation", "definition": "the process of making things uniform or similar everywhere, reducing diversity", "translation": "гомогенизация"},
    {"term": "supply chain", "definition": "the sequence of processes involved in producing and distributing a product from raw material to consumer", "translation": "цепочка поставок"},
    {"term": "inequality", "definition": "the unequal distribution of wealth, opportunities, or resources among people or countries", "translation": "неравенство"},
    {"term": "hybrid", "definition": "something that combines two or more different elements or cultural influences", "translation": "гибрид"}
  ],
  "comprehension_questions": [
    {"id": 1, "question": "What does globalisation refer to according to the passage?", "options": ["A) The spread of democracy to previously authoritarian countries", "B) The increasing interconnection of economies, cultures, and societies worldwide", "C) The migration of people from developing to developed countries", "D) The economic dominance of a small number of powerful nations"], "answer": "B", "explanation": "Globalisation describes the accelerating process by which economies, societies, and cultures around the world have become interconnected."},
    {"id": 2, "question": "What developments drove the acceleration of globalisation according to the passage?", "options": ["A) Military power and diplomatic agreements between governments", "B) Government subsidies for export industries", "C) Container shipping, commercial aviation, and the internet", "D) The introduction of a single global currency"], "answer": "C", "explanation": "Container shipping, commercial aviation, and the internet and mobile communication all drove the acceleration of globalisation."},
    {"id": 3, "question": "What economic benefit of globalisation does the passage mention?", "options": ["A) It eliminated inequality between all countries", "B) It lifted hundreds of millions out of extreme poverty in Asia, Latin America, and Africa", "C) It guaranteed safe working conditions for all factory workers worldwide", "D) It led to equal wages for workers in all countries"], "answer": "B", "explanation": "Globalisation produced significant economic growth, lifting hundreds of millions of people out of extreme poverty."},
    {"id": 4, "question": "What cultural concern does the passage raise about globalisation?", "options": ["A) Cultural exchange is too slow to have any real effect", "B) The spread of American popular culture threatens minority languages and local traditions", "C) Traditional cultures are becoming more isolated from global influences", "D) Digital technology has prevented meaningful cultural exchange"], "answer": "B", "explanation": "The global spread of American culture has threatened minority languages and local traditions — hundreds of languages are now endangered."},
    {"id": 5, "question": "What do supporters of globalisation argue according to the passage?", "options": ["A) That economic growth justifies any social or cultural cost", "B) That wealthier countries benefit most and should protect their advantages", "C) That the mixing of cultures produces new hybrid forms that enrich human experience", "D) That free trade agreements eliminate the need for government regulation"], "answer": "C", "explanation": "Supporters argue that cultural mixing produces new hybrid forms of music, art, and cuisine that enrich human experience."}
  ],
  "true_false_questions": [
    {"id": 1, "statement": "The passage argues that globalisation is an entirely new phenomenon that began after the Cold War.", "answer": false, "evidence": "Trade and cultural contact between distant regions have existed for millennia, though the speed and scale increased dramatically in the twentieth century."},
    {"id": 2, "statement": "Container shipping made it cheaper to transport goods across oceans.", "answer": true, "evidence": "Container shipping dramatically reduced the cost of transporting goods across oceans."},
    {"id": 3, "statement": "Workers in developing countries always benefit from safe conditions and fair wages through globalisation.", "answer": false, "evidence": "Workers in developing countries often face poor conditions and low wages despite contributing to global supply chains."},
    {"id": 4, "statement": "The passage presents both positive and negative effects of cultural globalisation.", "answer": true, "evidence": "Cultural globalisation has had similarly mixed effects — creating shared reference points while also threatening minority languages and local traditions."},
    {"id": 5, "statement": "The debate over the costs and benefits of globalisation has been fully resolved.", "answer": false, "evidence": "The debate about how to manage globalisation fairly and sustainably continues to define international political and economic discourse today."}
  ],
  "vocabulary_in_context": [
    {"id": 1, "sentence": "Economies, societies, and cultures around the world have become increasingly [BLANK] through the process of globalisation.", "options": ["A) divided", "B) competitive", "C) interconnected", "D) homogenised"], "answer": "C", "explanation": "Interconnected is the word used in the passage to describe how globalisation links the world together."},
    {"id": 2, "sentence": "Critics argue that globalisation has increased [BLANK] both between countries and within individual countries.", "options": ["A) diversity", "B) inequality", "C) instability", "D) trade"], "answer": "B", "explanation": "Inequality is specifically mentioned as a concern raised by critics of globalisation."},
    {"id": 3, "sentence": "Workers in developing countries often face poor conditions and low wages despite contributing to global [BLANK] that supply products to wealthy markets.", "options": ["A) demand", "B) competition", "C) supply chains", "D) corporations"], "answer": "C", "explanation": "Supply chains are the sequences of production and distribution processes — developing country workers often contribute to these chains with little reward."},
    {"id": 4, "sentence": "Supporters argue that cultural mixing produces new [BLANK] forms of music, art, and cuisine that enrich human experience.", "options": ["A) traditional", "B) commercial", "C) hybrid", "D) popular"], "answer": "C", "explanation": "Hybrid means something combining two or more different influences, which is what cultural mixing produces."}
  ],
  "critical_thinking": [
    {"id": 1, "question": "The passage presents both benefits and criticisms of globalisation. On balance, do you think globalisation has been more positive or more negative for the world? Give reasons.", "suggested_answer": "Globalisation has produced enormous economic gains, lifting hundreds of millions out of poverty and creating global supply chains that deliver affordable goods. However, these gains have been unevenly distributed, and the costs — environmental damage, job losses in manufacturing communities, cultural homogenisation — have fallen disproportionately on the most vulnerable. On balance, globalisation may be positive in its potential, but its actual outcomes depend heavily on whether governments and international institutions regulate it fairly and redistribute its benefits."},
    {"id": 2, "question": "The passage discusses concern that the spread of a dominant global culture leads to cultural homogenisation. How important is it to preserve local cultural diversity? What can be done to protect it?", "suggested_answer": "Cultural diversity is genuinely valuable — it represents the accumulated wisdom and creativity of human communities that have evolved in unique historical contexts. When languages die and local traditions disappear, humanity loses irreplaceable knowledge and ways of understanding the world. To protect local cultures, governments can invest in language education, support local artists and media, and promote indigenous cultural content. The goal should be diversity within interconnection — cultural exchange that strengthens rather than replaces local traditions."}
  ]
}$json$::jsonb
WHERE lesson_id = (
  SELECT l.id FROM english_lessons l
  JOIN english_modules m ON l.module_id = m.id
  JOIN english_courses c ON m.course_id = c.id
  WHERE c.title = 'B1 Intermediate' AND c.category = 'General English'
    AND m.order_index = 2 AND l.order_index = 7
) AND type = 'reading';